import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const chaptersDir = path.resolve(__dirname, '../src/data/chapters');
const bundlePath = path.resolve(__dirname, '../src/data/chapter_data.js');

console.log('Reading chapters from:', chaptersDir);

// Read all files in the directory
const files = fs.readdirSync(chaptersDir);

// Filter and sort files by numeric ID
const chapterFiles = files
  .filter(f => f.startsWith('chapter_') && f.endsWith('.json'))
  .map(f => {
    const id = parseInt(f.replace('chapter_', '').replace('.json', ''), 10);
    return { id, filename: f, filepath: path.join(chaptersDir, f) };
  })
  .sort((a, b) => a.id - b.id);

console.log(`Found ${chapterFiles.length} chapter JSON files.`);

// Load all chapters
const chapters = [];
for (const fileInfo of chapterFiles) {
  try {
    const content = fs.readFileSync(fileInfo.filepath, 'utf-8');
    const data = JSON.parse(content);
    // Double-check the ID matches
    if (data.id !== fileInfo.id) {
      console.warn(`Warning: File ID mismatch! File: ${fileInfo.filename}, content ID: ${data.id}`);
    }
    chapters.push(data);
  } catch (err) {
    console.error(`Error reading or parsing ${fileInfo.filename}:`, err);
    process.exit(1);
  }
}

// Generate the bundle content
const bundleContent = `// AUTO-GENERATED by scripts/bundleChapters.js — Do not edit manually.
export const MNN_DATA = ${JSON.stringify(chapters, null, 2)};
`;

fs.writeFileSync(bundlePath, bundleContent, 'utf-8');
console.log(`✅ Successfully generated bundle ${bundlePath} containing ${chapters.length} chapters.`);

// Generate the index content
const indexPath = path.resolve(__dirname, '../src/data/chapter_index.js');
const indexData = chapters.map(ch => ({
  id: ch.id,
  title: ch.title,
  desc: ch.desc,
  locked: ch.locked || false,
  vocabCount: ch.vocab ? ch.vocab.length : 0
}));
const indexContent = `// AUTO-GENERATED by scripts/bundleChapters.js — Do not edit manually.
export const MNN_INDEX = ${JSON.stringify(indexData, null, 2)};

// Cache for lazy-loaded full chapter data
const _chapterCache = new Map();

/**
 * Lazy-load full chapter data (vocab, grammar, workbook, exam, etc.)
 * Subsequent calls for the same ID are served from cache.
 * @param {number} id - chapter ID (0-50)
 * @returns {Promise<object>} Full chapter data object
 */
export async function loadChapter(id) {
  if (_chapterCache.has(id)) return _chapterCache.get(id);
  const mod = await import(\`./chapters/chapter_\${id}.json\`);
  const data = mod.default;
  _chapterCache.set(id, data);
  return data;
}
`;
fs.writeFileSync(indexPath, indexContent, 'utf-8');
console.log(`✅ Successfully generated index ${indexPath} containing ${indexData.length} chapter summaries.`);


// Output brief stats table
console.log('\n=== BUNDLE SUMMARY ===');
console.log('| Chapter | Title | Vocab | Grammar | Reibun | Workbook | Exam |');
console.log('|---------|-------|-------|---------|--------|----------|------|');
for (const ch of chapters) {
  const v = ch.vocab ? ch.vocab.length : 0;
  const g = ch.grammar ? ch.grammar.length : 0;
  const r = ch.reibun ? ch.reibun.length : 0;
  const w = ch.workbook ? ch.workbook.length : 0;
  const e = (ch.exam && typeof ch.exam === 'object' && !Array.isArray(ch.exam)) 
    ? (ch.exam.part1?.length || 0) + (ch.exam.part2?.length || 0) + (ch.exam.part3?.length || 0)
    : (ch.exam ? ch.exam.length : 0);
  console.log(`| ${ch.id.toString().padEnd(7)} | ${ch.title.substring(0, 30).padEnd(30)} | ${v.toString().padEnd(5)} | ${g.toString().padEnd(7)} | ${r.toString().padEnd(6)} | ${w.toString().padEnd(8)} | ${e.toString().padEnd(4)} |`);
}
